import{_ as i,g as a,h as n,U as l}from"./chunks/vitepress-theme-teek.BeZX561D.js";const g=JSON.parse('{"title":"模块化编程原则梳理与总结","description":"系统梳理模块化编程的六大核心原则：单一职责、高内聚低耦合、粒度设计、命名规范及模块版本管理，附详细的工程实践建议与避坑指南。","frontmatter":{"date":"2024-05-17T22:30:50.000Z","title":"模块化编程原则梳理与总结","tldr":"掌握高内聚低耦合原则：模块化编程的设计准则与粒度控制。","description":"系统梳理模块化编程的六大核心原则：单一职责、高内聚低耦合、粒度设计、命名规范及模块版本管理，附详细的工程实践建议与避坑指南。","permalink":"/fullstack/module-programming-principles-best-practices","abstract":"如果说掌握模块化语法是术，那么理解其背后的设计原则就是道。单一职责原则强调模块只应有一个被改变的原因，避免 God Object 反模式。高内聚低耦合是衡量模块质量的终极标准——模块内部元素联系紧密，模块之间依赖关系尽可能简单。粒度设计要求单个模块保持在 100-500 行之间，功能能用一句话清晰描述，出现多分支复杂逻辑时通常是拆分信号。命名规范统一团队沟通语境（kebab-case 文件名、camelCase 方法名、PascalCase 类名）。模块版本管理遵循 SemVer 语义化版本，为公共模块的维护者与使用者建立契约。强调清晰的模块边界是 AI 辅助编程时代 AI 准确理解代码的前提。","tags":["concept","solid-principles","code-organization","best-practices","naming-conventions"],"categories":["全栈","全栈基础素养","模块化编程实践指南"]},"headers":[],"relativePath":"01.全栈/80.全栈基础素养/20.模块化编程实践指南/5.模块化编程原则与最佳实践.md","filePath":"01.全栈/80.全栈基础素养/20.模块化编程实践指南/5.模块化编程原则与最佳实践.md"}'),p={name:"01.全栈/80.全栈基础素养/20.模块化编程实践指南/5.模块化编程原则与最佳实践.md"};function h(e,s,t,k,r,d){return n(),a("div",null,[...s[0]||(s[0]=[l("",31)])])}const c=i(p,[["render",h]]);export{g as __pageData,c as default};
